    if (parsed.size != settingsNodes.size) {
      Left("Invalid <setting> element encountered")
    } else {
      Right(parsed.map(s => s.key -> s.value).toMap)
    }
  }

  private def parseSettingNode(node: Node): Option[ConfigSetting] = {
    val keyOpt = (node \ "@key").text.trim match {
      case "" => None
      case v  => Some(v)
    }

    val valueOpt =
      if ((node \ "@value").nonEmpty) Some((node \ "@value").text)
      else {
        val textValue = node.text.trim
